function countingSort(arr, exp) {
	let n = arr.length;
	let output = new Array(n);
	let count = new Array(10).fill(0);
	for (let i = 0; i < n; i++) {
		count[Math.floor(arr[i] / exp) % 10]++;
	}
	for (let i = 1; i < 10; i++) {
		count[i] += count[i - 1];
	}
	for (let i = n - 1; i >= 0; i--) {
		output[count[Math.floor(arr[i] / exp) % 10] - 1] = arr[i];
		count[Math.floor(arr[i] / exp) % 10]--;
	}
	for (let i = 0; i < n; i++) {
		arr[i] = output[i];
	}
}

